#include <stdio.h>
#include <stdlib.h>

// Structure to represent a process
typedef struct Process {
 int arrival_time;
 int burst_time;
} Process;

// Function to sort processes by arrival time
void sort_processes(Process *processes, int n) {
 // Bubble sort implementation
 for (int i = 0; i < n - 1; i++) {
 for (int j = 0; j < n - i - 1; j++) {
 if (processes[j].arrival_time > processes[j + 1].arrival_time) {
 // Swap processes
 Process temp = processes[j];
 processes[j] = processes[j + 1];
 processes[j + 1] = temp;
 }
 }
 }
}

// Function to implement FCFS scheduling
void fcfs_scheduling(Process *processes, int n) {
 // Sort processes by arrival time
 sort_processes(processes, n);

 // Initialize schedule and current time
 int current_time = 0;

 // Iterate over processes in sorted order
 for (int i = 0; i < n; i++) {
 // Add process to schedule at current time
 printf("Process %d: %d - %d\n", i + 1, current_time, current_time + processes[i].burst_time);
 // Increment current time by burst time
 current_time += processes[i].burst_time;
 }
}

// Example usage
int main() {
 Process processes[] = {{0, 24}, {0, 3}, {0, 3}};
 int n = sizeof(processes) / sizeof(processes[0]);
 fcfs_scheduling(processes, n);
 return 0;
}
